detailed_optimizations.code_changes:
将 i/j/k 改为分块循环，例如 Bi,Bj,Bk；在 (ii,jj,kk) tile 内做小块乘加。示例(伪码)：
for(ii=0;ii<NI;ii+=Bi)
 for(jj=0;jj<NJ;jj+=Bj){
  // 先对 C tile 做 beta 缩放
  for(i=ii;i<min(ii+Bi,NI);++i)
   for(j=jj;j<min(jj+Bj,NJ);++j) C[i][j]*=beta;
  for(kk=0;kk<NK;kk+=Bk)
   for(i=ii;i<min(ii+Bi,NI);++i)
    for(k=kk;k<min(kk+Bk,NK);++k){
      const DATA_TYPE a = alpha*A[i][k];
      // j 内层保持连续访问
      for(j=jj;j<min(jj+Bj,NJ);++j) C[i][j] += a*B[k][j];
    }
 }
推荐起始块大小：Bk=64~256（取决于 L1/L2），Bj=64~256，Bi=4~16（配合寄存器微核）。

在最外层 tile 上并行：
#pragma omp parallel for collapse(2) schedule(static)
for(ii=0;ii<NI;ii+=Bi)
 for(jj=0;jj<NJ;jj+=Bj) { ... }
注意：若使用 packing，Bpack 需每线程私有或按 tile 分配，避免写冲突；C tile 不重叠即可无锁。

将 j 内层改为连续写 tmp[i][j]，把 alpha*A[i][k] 提升为寄存器，避免在 k 循环内重复乘 alpha；并用 restrict/对齐提示帮助编译器向量化。
示例（保持语义）：
for (i=0;i<NI;i++) {
  for (j=0;j<NJ;j++) tmp[i][j]=0;
  for (k=0;k<NK;k++) {
    DATA_TYPE aik = alpha * A[i][k];
    #pragma omp simd
    for (j=0;j<NJ;j++) tmp[i][j] += aik * B[k][j];
  }
}
同时在函数形参上加 __restrict__（或编译选项 -fno-alias）并确保 B[k][j] 行连续存储。

对 (i,j,k) 做 2D/3D 分块以提升 A/B/C 的复用并降低 LLC miss。示例（第一段）：
for (ii=0;ii<NI;ii+=Ti)
 for (kk=0;kk<NK;kk+=Tk)
  for (jj=0;jj<NJ;jj+=Tj)
   for (i=ii;i<min(ii+Ti,NI);i++)
    for (k=kk;k<min(kk+Tk,NK);k++) {
      DATA_TYPE aik = alpha*A[i][k];
      #pragma omp simd
      for (j=jj;j<min(jj+Tj,NJ);j++) tmp[i][j]+=aik*B[k][j];
    }
第二段同理对 (i,j,k)=(i, l, j) 分块：D[i][l] += tmp[i][j]*C[j][l]。
块大小经验：Tj/Tl 取 64~256（按元素与向量宽度对齐），Tk/Tj 组合使得 A 子块 + B 子块能放入 L2/L3（需按平台调参）。

将 D[i][j]*=beta 与累加融合到同一写回路径，减少一次对 D 的读写；并把 k 外提以连续访问 C[k][j]。
示例：
for (i=0;i<NI;i++) {
  for (j=0;j<NL;j++) D[i][j] *= beta;
  for (k=0;k<NJ;k++) {
    DATA_TYPE tik = tmp[i][k];
    #pragma omp simd
    for (j=0;j<NL;j++) D[i][j] += tik * C[k][j];
  }
}
若允许更激进：把 beta 缩放并入第一次写 D 的循环（保持数值一致性通常没问题，但浮点舍入路径会变化）。

将 i-k-j 改为 i-j-k（或分块 i/j 后在块内做 k 累加），使内层 k 连续访问 A[i][k] 与 A[j][k]（两者均为行内连续）。示例：

for (int i=0;i<_PB_N;i++) {
  for (int j=0;j<=i;j++) {
    DATA_TYPE cij = C[i][j]*beta;
    #pragma omp simd reduction(+:cij)
    for (int k=0;k<_PB_M;k++) cij += alpha*A[i][k]*A[j][k];
    C[i][j]=cij;
  }
}

进一步分块（推荐）：
const int BI=32,BJ=32,BK=64;
for (int ii=0; ii<_PB_N; ii+=BI)
  for (int jj=0; jj<=ii; jj+=BJ)
    for (int kk=0; kk<_PB_M; kk+=BK)
      for (int i=ii; i<min(ii+BI,_PB_N); ++i)
        for (int j=jj; j<min(jj+BJ,i+1); ++j) {
          DATA_TYPE cij = (kk==0)? C[i][j]*beta : C[i][j];
          for (int k=kk; k<min(kk+BK,_PB_M); ++k)
            cij += alpha*A[i][k]*A[j][k];
          C[i][j]=cij;
        }

外层 i 之间无写冲突（每个 i 写 C[i][0..i]），可并行：
#pragma omp parallel for schedule(static)
for (int i=0;i<_PB_N;i++) {
  for (int j=0;j<=i;j++) { ... }
}

若采用分块：
#pragma omp parallel for collapse(2) schedule(static)
for (int ii=0; ii<_PB_N; ii+=BI)
  for (int jj=0; jj<=ii; jj+=BJ) { ... }

将内层结构改为：先对 j<=i 初始化 tmp = C[i][j]*beta；然后对 k 累加到 tmp；最后写回 C[i][j]=tmp。示例：
for(i=0;i<n;i++){
  for(j=0;j<=i;j++) C[i][j]*=beta; // 或融合到下面
  for(j=0;j<=i;j++){
    DATA_TYPE cij = C[i][j];
    cij *= beta;
    for(k=0;k<m;k++){
      cij += alpha*(A[j][k]*B[i][k] + B[j][k]*A[i][k]);
    }
    C[i][j]=cij;
  }
}
注意：这会改变访问顺序（j 外提），但数学等价；同时显著减少对 C 的反复加载/存储。

在 kernel 前预处理一次转置：A_T[k][i]=A[i][k], B_T[k][i]=B[i][k]（代价 O(NM)）。随后在内层使用连续访问：A_T[k][j], B_T[k][j]。
示例（伪码）：
// precompute
for(i=0;i<n;i++) for(k=0;k<m;k++){ A_T[k][i]=A[i][k]; B_T[k][i]=B[i][k]; }
// compute
for(i=0;i<n;i++){
  for(j=0;j<=i;j++){
    DATA_TYPE cij = C[i][j]*beta;
    for(k=0;k<m;k++){
      cij += alpha*(A_T[k][j]*B_T[k][i] + B_T[k][j]*A_T[k][i]);
    }
    C[i][j]=cij;
  }
}
这样 k 内层对 A_T/B_T 是 unit-stride，显著改善 L1/L2 命中与硬件预取。

1) 给指针加 restrict（若允许改签名）：DATA_TYPE * restrict A,...
2) 确保数据对齐（polybench 通常已对齐，但可用 aligned_alloc/编译器属性）。
3) 在 k 循环上加编译器指示：
#pragma omp simd reduction(+:cij)
for(k=0;k<m;k++) { ... }
更稳妥做法是把 (A[j][k]*B[i][k] + B[j][k]*A[i][k]) 写成可被 FMA 识别的形式，并将 alpha 提前提取：
DATA_TYPE a = alpha;
...
cij += a*A[j][k]*B[i][k];
cij += a*B[j][k]*A[i][k];
并开启 -O3 -ffast-math（若允许）/ -march=native。

将三角域按块处理（例如 BI×BJ），并对 k 做 BK 分块：
for(ii=0; ii<n; ii+=BI)
  for(jj=0; jj<=ii; jj+=BJ) {
    // 处理块 C[ii:ii+BI, jj:jj+BJ]（注意三角边界）
    // 先对该块乘 beta
    for(kk=0; kk<m; kk+=BK) {
      // 使用 A/B 的子块做 rank-k 更新
      // 可在块内对 C 元素寄存器累加
    }
  }
实现要处理 jj+BJ 可能超过 ii+BI 的三角裁剪。若不想手写，可直接调用 BLAS：dsyr2k/ssyr2k（最佳）。

示例（保持语义）：

for (r=0;r<NR;r++)
  for (q=0;q<NQ;q++) {
    // sum 清零
    for (p=0;p<NP;p++) sum[p]=0;

    const DATA_TYPE * __restrict arow = &A[r][q][0];
    for (int ss=0; ss<NP; ss++) {
      DATA_TYPE a = arow[ss];
      const DATA_TYPE * __restrict c4row = &C4[ss][0];
      // p 分块，利于向量化与缓存
      for (int pp=0; pp<NP; pp+=TP) {
        #pragma omp simd
        for (int p=pp; p<pp+TP && p<NP; p++)
          sum[p] += a * c4row[p];
      }
    }
    // 写回
    for (p=0;p<NP;p++) A[r][q][p]=sum[p];
  }

其中 TP 可取 32/64/128（按 SIMD 宽度与 L1 容量调参）。

并行化外层：
#pragma omp parallel
{
  // 每线程私有 sum，避免共享写
  DATA_TYPE *sum_priv = (DATA_TYPE*) aligned_alloc(64, NP*sizeof(DATA_TYPE));

  #pragma omp for collapse(2) schedule(static)
  for (int r=0;r<NR;r++)
    for (int q=0;q<NQ;q++) {
      for (int p=0;p<NP;p++) sum_priv[p]=0;
      for (int s=0;s<NP;s++) {
        DATA_TYPE a = A[r][q][s];
        #pragma omp simd
        for (int p=0;p<NP;p++) sum_priv[p] += a * C4[s][p];
      }
      for (int p=0;p<NP;p++) A[r][q][p]=sum_priv[p];
    }

  free(sum_priv);
}

注意：不要复用原全局 sum（否则线程间冲突）。

示例（寄存器 tile，适合 NP 大且 SIMD 友好）：
for (int pp=0; pp<NP; pp+=TP) {
  DATA_TYPE acc[TP];
  for (int i=0;i<TP;i++) acc[i]=0;
  for (int s=0;s<NP;s++) {
    DATA_TYPE a=A[r][q][s];
    #pragma omp simd
    for (int i=0;i<TP && pp+i<NP;i++) acc[i]+=a*C4[s][pp+i];
  }
  for (int i=0;i<TP && pp+i<NP;i++) A[r][q][pp+i]=acc[i];
}

这样可去掉对 sum[] 的反复读写（只在寄存器中累加）。

核心问题：对每个 j 都要两次遍历 i（一次算 R[k,j]，一次更新 A[:,j]），且每次都要读 Q[:,k]。
1) 分块 j（JB）以复用 Q[:,k] 并提高 A 的空间局部性：
   for (j0=k+1; j0<_PB_N; j0+=JB) {
     int jmax = min(_PB_N, j0+JB);
     // 计算一块 R[k][j]
     for (j=j0; j<jmax; ++j) R[k][j]=0;
     for (i=0; i<_PB_M; ++i) {
       DATA_TYPE q = Q[i][k];
       #pragma omp simd
       for (j=j0; j<jmax; ++j) R[k][j] += q * A[i][j];
     }
     // 更新 A[:,j]
     for (i=0; i<_PB_M; ++i) {
       DATA_TYPE q = Q[i][k];
       #pragma omp simd
       for (j=j0; j<jmax; ++j) A[i][j] -= q * R[k][j];
     }
   }
   这样把内层从“按列访问 A[i][j] 的跨步”变为“按行连续访问 A[i][j]”，更符合 C 行主序。
2) 进一步：把 R[k][j] 的计算与更新融合到同一 i 循环块内（两阶段仍需 R[k][j] 完成后才能更新，除非使用两遍 i；但可以对 i 分块：先在 i-block 内累加 partial_R[j]，完成后再做更新，减少对 A 的重复读写）。
3) 调用 BLAS：
   - R[k,k+1:] = Q[:,k]^T * A[:,k+1:]  => GEMV（或把 A 子矩阵视作列集合）
   - A[:,k+1:] -= Q[:,k] * R[k,k+1:]    => GER（rank-1 update）
   若使用 cblas_dgemv + cblas_dger（或更高效的 dgemm 形式的 blocked MGS），通常显著提升。
4) OpenMP 并行：对 j0 块并行（每个线程处理一段 j），避免对 R[k][j] 的写冲突：
   #pragma omp parallel for schedule(static)
   for (j0=...)
   注意：点积阶段对 i 的循环在每个线程内执行，线程数过多会受内存带宽限制。
